/**
 * Defines the possible abi call signatures.
 */
export type HyperSwapSignatures = keyof HyperSwapTypes['methods']
/**
 * Defines the possible abi call signatures for methods that return a non-void value.
 */
export type HyperSwapNonVoidMethodSignatures = keyof HyperSwapTypes['methods'] extends infer T ? T extends keyof HyperSwapTypes['methods'] ? MethodReturn<T> extends void ? never : T  : never : never
/**
 * Defines an object containing all relevant parameters for a single call to the contract.
 */
export type CallParams<TArgs> = Expand<
  Omit<AppClientMethodCallParams, 'method' | 'args' | 'onComplete'> &
    {
      /** The args for the ABI method call, either as an ordered array or an object */
      args: Expand<TArgs>
    }
>
/**
 * Maps a method signature from the HyperSwap smart contract to the method's arguments in either tuple or struct form
 */
export type MethodArgs<TSignature extends HyperSwapSignatures> = HyperSwapTypes['methods'][TSignature]['argsObj' | 'argsTuple']
/**
 * Maps a method signature from the HyperSwap smart contract to the method's return type
 */
export type MethodReturn<TSignature extends HyperSwapSignatures> = HyperSwapTypes['methods'][TSignature]['returns']

/**
 * Defines the shape of the keyed global state of the application.
 */
export type GlobalKeysState = HyperSwapTypes['state']['global']['keys']

/**
 * Defines the shape of the keyed box state of the application.
 */
export type BoxKeysState = HyperSwapTypes['state']['box']['keys']



